import Foundation

let questions1: [QuizQuestion] = [
    // GÊNESIS E CRIAÇÃO (1-167)
    QuizQuestion(id:1, question:"Em quantos dias Deus criou o mundo?", options:["5 dias","6 dias","7 dias","10 dias"], correctIndex:1, explanation:"Deus criou o mundo em 6 dias e no sétimo descansou, abençoando-o como dia de repouso.", reference:"Gênesis 1:31–2:2", category:.genesis, propheticMeaning:"Os 6 dias de criação apontam para os 6.000 anos da história humana, e o sétimo dia de descanso prefigura o Reino Milenar de Cristo, quando toda a criação repousará sob seu governo."),
    QuizQuestion(id:2, question:"Como se chamava o primeiro homem criado por Deus?", options:["Noé","Abraão","Adão","Moisés"], correctIndex:2, explanation:"Deus formou o homem do pó da terra e soprou em suas narinas o fôlego de vida.", reference:"Gênesis 2:7", category:.genesis, propheticMeaning:"Adão é tipo de Cristo: o primeiro Adão trouxe morte pela desobediência; o último Adão (Jesus) traz vida pela obediência perfeita (1 Co 15:45)."),
    QuizQuestion(id:3, question:"Qual era o nome da esposa de Adão?", options:["Sara","Rute","Ester","Eva"], correctIndex:3, explanation:"Eva foi criada de uma costela de Adão para ser sua companheira, a mãe de todos os viventes.", reference:"Gênesis 2:22; 3:20", category:.genesis, propheticMeaning:"Eva tirada do lado de Adão enquanto ele dormia é tipo da Igreja nascida do lado traspassado de Cristo na cruz, unida a Ele como noiva."),
    QuizQuestion(id:4, question:"Quantos dias e noites durou o dilúvio no tempo de Noé?", options:["40","20","30","50"], correctIndex:0, explanation:"Choveu quarenta dias e quarenta noites, e Noé, sua família e os animais foram preservados na arca.", reference:"Gênesis 7:12", category:.genesis, propheticMeaning:"A arca de Noé é tipo da salvação em Cristo: assim como somente dentro da arca havia segurança, somente em Cristo há salvação do juízo de Deus (1 Pe 3:20-21)."),
    QuizQuestion(id:5, question:"Qual sinal Deus colocou no céu como aliança com Noé?", options:["Estrela cadente","Arco-íris","Nuvem brilhante","Raio"], correctIndex:1, explanation:"O arco-íris foi o sinal da aliança de Deus de nunca mais destruir a terra com dilúvio.", reference:"Gênesis 9:13", category:.genesis, propheticMeaning:"O arco-íris em torno do trono de Deus em Apocalipse 4:3 mostra que a aliança da graça permanece eternamente, e Cristo é o cumprimento de toda promessa divina."),
    QuizQuestion(id:6, question:"O que Deus criou no primeiro dia?", options:["O sol e a lua","Os peixes","A luz","As plantas"], correctIndex:2, explanation:"No primeiro dia Deus disse 'Haja luz' e a luz foi feita, separando-a das trevas.", reference:"Gênesis 1:3-5", category:.genesis, propheticMeaning:"A luz criada antes do sol aponta para Cristo, a Luz do mundo (Jo 8:12), que existia antes de toda criação e dispersa as trevas do pecado."),
    QuizQuestion(id:7, question:"O que Deus criou no quarto dia?", options:["Os peixes e as aves","Os animais terrestres","O homem","O sol, a lua e as estrelas"], correctIndex:3, explanation:"No quarto dia Deus criou os grandes luminares: o sol para governar o dia e a lua para governar a noite.", reference:"Gênesis 1:14-19", category:.genesis, propheticMeaning:"O sol é tipo de Cristo, o Sol de Justiça (Ml 4:2); a lua, que reflete a luz do sol, é tipo da Igreja, que reflete a glória de Cristo para o mundo."),
    QuizQuestion(id:8, question:"Em qual jardim Deus colocou Adão e Eva?", options:["Jardim do Éden","Jardim de Getsêmani","Jardim de Salomão","Jardim de Josafá"], correctIndex:0, explanation:"Deus plantou um jardim no Éden e ali colocou o homem que havia formado para cultivá-lo e guardá-lo.", reference:"Gênesis 2:8", category:.genesis, propheticMeaning:"O Éden é o protótipo do Reino de Deus na terra. Cristo veio restaurar o que Adão perdeu, e o Apocalipse descreve a Nova Jerusalém com a árvore da vida, o Éden restaurado."),
    QuizQuestion(id:9, question:"Qual fruto Adão e Eva foram proibidos de comer?", options:["Figo","Do conhecimento","Maçã","Da videira"], correctIndex:1, explanation:"Deus proibiu comer do fruto da árvore do conhecimento do bem e do mal, sob pena de morte.", reference:"Gênesis 2:17", category:.genesis, propheticMeaning:"A proibição aponta para a necessidade de obediência. Cristo, o segundo Adão, obedeceu plenamente onde o primeiro Adão falhou, trazendo justiça em vez de condenação."),
    QuizQuestion(id:10, question:"Quem tentou Adão e Eva no jardim do Éden?", options:["Um anjo","Um estranho","A serpente","Um querubim"], correctIndex:2, explanation:"A serpente, mais astuta que todos os animais, enganou Eva dizendo que ela seria como Deus se comesse o fruto proibido.", reference:"Gênesis 3:1-5", category:.genesis, propheticMeaning:"A serpente do Éden é identificada em Apocalipse 12:9 como Satanás. Assim como ele enganou Eva, tenta enganar a Igreja; mas Cristo esmagará sua cabeça (Gn 3:15)."),
    QuizQuestion(id:11, question:"Qual foi a consequência imediata de Adão e Eva comerem o fruto proibido?", options:["Foram transformados em animais","Foram expulsos imediatamente","Adoeceram gravemente","Perceberam que estavam nus e"], correctIndex:3, explanation:"Após comer o fruto, os olhos de ambos se abriram e perceberam que estavam nus, sentindo vergonha pela primeira vez.", reference:"Gênesis 3:7", category:.genesis, propheticMeaning:"A vergonha da nudez revela a perda da glória de Deus que os envolvia. Cristo veio nos revestir de sua justiça, cobrindo nossa vergonha com suas vestes de salvação."),
    QuizQuestion(id:12, question:"Com o que Deus fez as vestes para cobrir Adão e Eva?", options:["Peles de animais","Penas de aves","Folhas de figueira","Linho"], correctIndex:0, explanation:"Deus fez vestes de peles de animais para cobrir Adão e Eva, o que implica o primeiro sacrifício de sangue.", reference:"Gênesis 3:21", category:.genesis, propheticMeaning:"As peles de animais são o primeiro sacrifício substituto na Bíblia, apontando profeticamente para o sacrifício de Cristo, cujo sangue nos reveste de justiça diante de Deus."),
    QuizQuestion(id:13, question:"Qual foi a promessa de Deus na maldição da serpente em Gênesis 3:15?", options:["A serpente nunca mais faria mal","A descendência da mulher esmagaria","Adão se tornaria imortal","Eva teria muitos filhos"], correctIndex:1, explanation:"Deus prometeu que haveria inimizade entre a descendência da mulher e a serpente, e que aquela esmagaria a cabeça desta.", reference:"Gênesis 3:15", category:.genesis, propheticMeaning:"Gênesis 3:15 é o Protoevangelium, a primeira profecia messiânica. A 'descendência da mulher' é Jesus Cristo, que na cruz destruiu o poder de Satanás, esmagando sua cabeça."),
    QuizQuestion(id:14, question:"Quem foram os dois primeiros filhos de Adão e Eva?", options:["Abel e Sete","Caim e Sete","Caim e Abel","Noé e Abel"], correctIndex:2, explanation:"Caim, o primogênito, era agricultor; Abel, o segundo, era pastor de ovelhas.", reference:"Gênesis 4:1-2", category:.genesis, propheticMeaning:"Caim e Abel representam dois tipos de adoração: a da carne (ofertas sem fé) e a do espírito (ofertas pela fé). Abel é tipo de Cristo, o justo que derramou sangue."),
    QuizQuestion(id:15, question:"Por que Deus aceitou a oferta de Abel e não a de Caim?", options:["Abel ofereceu mais","Caim ofereceu frutas podres","Deus não explica","Abel ofereceu com fé e os"], correctIndex:3, explanation:"Abel ofereceu os primogênitos e a gordura do rebanho com fé; Hebreus 11:4 diz que foi pela fé que Abel ofereceu sacrifício mais excelente.", reference:"Gênesis 4:3-5; Hebreus 11:4", category:.genesis, propheticMeaning:"A oferta de sangue de Abel aponta para a necessidade de um sacrifício expiatório. Hebreus 12:24 diz que o sangue de Jesus fala coisas melhores do que o sangue de Abel."),
    QuizQuestion(id:16, question:"O que Caim fez com seu irmão Abel?", options:["Matou-o no campo","Expulsou-o de casa","Roubou suas ovelhas","Vendeu-o como escravo"], correctIndex:0, explanation:"Tomado de ciúme e ira, Caim matou Abel no campo, cometendo o primeiro homicídio da história.", reference:"Gênesis 4:8", category:.genesis, propheticMeaning:"Abel, o justo morto injustamente por seu irmão, é tipo de Cristo, morto pelos que deveriam amá-lo. João diz que Caim era do maligno e matou Abel porque suas obras eram más (1 Jo 3:12)."),
    QuizQuestion(id:17, question:"Com qual sinal Deus protegeu Caim após o assassinato de Abel?", options:["Uma espada de fogo","Um sinal na testa","Uma nuvem ao redor dele","Um anjo guardião"], correctIndex:1, explanation:"Deus colocou um sinal em Caim para que ninguém que o encontrasse o matasse, preservando sua vida apesar do crime.", reference:"Gênesis 4:15", category:.genesis, propheticMeaning:"Mesmo no julgamento, Deus mostrou misericórdia a Caim. Isso prefigura a graça de Deus que protege e preserva até os pecadores, dando-lhes tempo para o arrependimento."),
    QuizQuestion(id:18, question:"Qual era o nome do filho de Adão e Eva que substituiu Abel?", options:["Enoque","Noé","Sete","Lameque"], correctIndex:2, explanation:"Deus concedeu a Adão e Eva outro filho chamado Sete, pelo qual continuou a linhagem que levaria ao Messias.", reference:"Gênesis 4:25", category:.genesis, propheticMeaning:"A linhagem de Sete leva diretamente a Noé e depois a Abraão e, por fim, a Jesus Cristo. Deus preservou a linha messiânica mesmo depois da tragédia de Caim."),
    QuizQuestion(id:19, question:"Quantos anos viveu Matusalém, o homem mais velho da Bíblia?", options:["750 anos","850 anos","999 anos","969 anos"], correctIndex:3, explanation:"Matusalém viveu 969 anos, sendo o homem com maior longevidade registrada na Bíblia.", reference:"Gênesis 5:27", category:.genesis, propheticMeaning:"As longas vidas dos patriarcas pré-diluvianos mostram a paciência de Deus. Curiosamente, Matusalém morreu no ano do dilúvio, como se Deus esperasse até o último momento para o juízo."),
    QuizQuestion(id:20, question:"O que a Bíblia diz sobre Enoque, pai de Matusalém?", options:["Ele foi levado por Deus sem passar","Ele morreu afogado","Ele construiu a primeira cidade","Ele foi o primeiro sacerdote"], correctIndex:0, explanation:"Enoque andou com Deus e não foi achado mais, porque Deus o tomou para si, sem experimentar a morte.", reference:"Gênesis 5:24", category:.genesis, propheticMeaning:"Enoque é tipo dos crentes que serão arrebatados sem passar pela morte na volta de Cristo (1 Ts 4:17). Sua vida de comunhão com Deus é o modelo do cristão que caminha com Deus diariamente."),
    QuizQuestion(id:21, question:"Quantas pessoas entraram na arca de Noé?", options:["4","8","6","12"], correctIndex:1, explanation:"Oito pessoas entraram na arca: Noé, sua esposa, seus três filhos e as esposas deles.", reference:"Gênesis 7:13; 1 Pedro 3:20", category:.genesis, propheticMeaning:"As oito pessoas salvas pela arca prefiguram a ressurreição e nova vida em Cristo. O número oito na Bíblia representa novo começo — Jesus ressuscitou no oitavo dia (domingo após o sábado)."),
    QuizQuestion(id:22, question:"Quantas de cada espécie de animal impuro Noé levou para a arca?", options:["4","7","2","10"], correctIndex:2, explanation:"Dos animais impuros, Noé levou dois de cada espécie, um macho e uma fêmea; dos animais puros levou sete pares.", reference:"Gênesis 7:2-3", category:.genesis, propheticMeaning:"A distinção entre animais puros e impuros aponta para o sistema levítico de santidade que viria depois, prefigurando Cristo que purifica o que era impuro e nos declara santos diante de Deus."),
    QuizQuestion(id:23, question:"Qual pássaro Noé enviou primeiro da arca para verificar se as águas tinham baixado?", options:["Pomba","Águia","Pardal","Corvo"], correctIndex:3, explanation:"Noé enviou primeiro um corvo, que saía e voltava até as águas secarem. Depois enviou uma pomba.", reference:"Gênesis 8:7-8", category:.genesis, propheticMeaning:"O corvo, ave impura que se alimenta de carcaças, não retornou, simbolizando o homem carnal. A pomba, que voltou com o ramo de oliveira, é tipo do Espírito Santo que traz paz e novas boas."),
    QuizQuestion(id:24, question:"O que a pomba trouxe no bico quando voltou pela segunda vez até Noé?", options:["Um ramo de oliveira","Uma folha de figueira","Uma espiga de trigo","Uma flor"], correctIndex:0, explanation:"A pomba voltou trazendo no bico um ramo verde de oliveira, sinal de que as águas tinham baixado e a vida renascia.", reference:"Gênesis 8:11", category:.genesis, propheticMeaning:"O ramo de oliveira trazido pela pomba é símbolo de paz entre Deus e a humanidade. Cristo é o príncipe da paz que reconcilia o homem com Deus após o juízo do pecado."),
    QuizQuestion(id:25, question:"Quais foram os três filhos de Noé?", options:["Abraão, Isaque e Jacó","Sem, Cam e Jafé","Caim, Abel e Sete","Rúben, Simeão e Levi"], correctIndex:1, explanation:"Os três filhos de Noé foram Sem, Cam e Jafé, de quem se originou toda a humanidade após o dilúvio.", reference:"Gênesis 9:18", category:.genesis, propheticMeaning:"De Sem veio a linhagem semítica que levaria ao povo de Israel e ao Messias. A bênção de Noé sobre Sem ('Bendito seja o Senhor, Deus de Sem') é profecia da linha messiânica."),
    QuizQuestion(id:26, question:"Por que Deus confundiu as línguas no episódio da Torre de Babel?", options:["Para punir a idolatria","Para criar as nações","Para impedir que os homens realizassem","Para separar os malvados dos justos"], correctIndex:2, explanation:"Os homens queriam construir uma torre até o céu para fazer um nome para si. Deus confundiu as línguas para espalhar a humanidade pela terra.", reference:"Gênesis 11:4-9", category:.genesis, propheticMeaning:"A divisão das línguas em Babel é revertida no Pentecostes (At 2), quando o Espírito Santo une pessoas de todas as nações sob um mesmo evangelho, prefigurando a unidade final do povo de Deus."),
    QuizQuestion(id:27, question:"Em qual terra Abraão nasceu antes de Deus chamá-lo?", options:["Canaã","Harã","Egito","Ur dos Cald"], correctIndex:3, explanation:"Abraão, chamado originalmente de Abrão, nasceu em Ur dos Caldeus, na Mesopotâmia, antes de Deus chamá-lo para Canaã.", reference:"Gênesis 11:31", category:.genesis, propheticMeaning:"Abraão deixando Ur em resposta à chamada de Deus é tipo de todo crente que abandona o mundo em resposta ao chamado de Cristo, peregrinando em direção à cidade celestial."),
    QuizQuestion(id:28, question:"Qual promessa Deus fez a Abraão quando o chamou?", options:["Que todas as famílias da terra seriam","Que ele viveria mil anos","Que ele conquistaria todos os reinos","Que nunca teria inimigos"], correctIndex:0, explanation:"Deus prometeu a Abraão que faria dele uma grande nação e que todas as famílias da terra seriam benditas nele.", reference:"Gênesis 12:2-3", category:.genesis, propheticMeaning:"A promessa de que 'todas as famílias da terra serão benditas' é cumprida em Jesus Cristo, descendente de Abraão, no qual judeus e gentios recebem a bênção da salvação (Gl 3:8)."),
    QuizQuestion(id:29, question:"Quem era a esposa de Abraão?", options:["Rebeca","Sara","Lea","Raquel"], correctIndex:1, explanation:"Sara, chamada antes de Sarai, era esposa de Abraão e a quem Deus prometeu um filho na velhice.", reference:"Gênesis 17:15-16", category:.genesis, propheticMeaning:"Sara, mulher livre, é tipo da aliança da graça (Gl 4:22-31). Paulo usa Sara e Agar para ilustrar a diferença entre a lei (escravidão) e a graça (liberdade em Cristo)."),
    QuizQuestion(id:30, question:"Quem era Lot em relação a Abraão?", options:["Irmão","Filho","Sobrinho","Genro"], correctIndex:2, explanation:"Lot era filho de Harã, irmão de Abraão, portanto sobrinho de Abraão. Acompanhou seu tio na jornada para Canaã.", reference:"Gênesis 12:5", category:.genesis, propheticMeaning:"A separação entre Abraão e Lot ilustra que o caminho da fé e o caminho da escolha carnal produzem destinos diferentes. Abraão escolheu pela fé; Lot, pelo que seus olhos viam."),
    QuizQuestion(id:31, question:"Qual era o nome original de Abraão antes de Deus mudá-lo?", options:["Aram","Arão","Abimeleque","Abrão"], correctIndex:3, explanation:"O nome original era Abrão ('pai exaltado'). Deus o mudou para Abraão ('pai de multidões') como sinal da aliança.", reference:"Gênesis 17:5", category:.genesis, propheticMeaning:"A mudança de nome significa uma nova identidade e chamado divino. Em Cristo, também recebemos novo nome e nova identidade — somos chamados filhos de Deus (Jo 1:12)."),
    QuizQuestion(id:32, question:"O que Deus exigiu de Abraão e de todos os varões como sinal da aliança?", options:["A circuncisão","Oferecer um carneiro por ano","Guardar o sábado","Construir um altar"], correctIndex:0, explanation:"Deus ordenou a circuncisão de todo varão como sinal perpétuo da aliança com Abraão e seus descendentes.", reference:"Gênesis 17:10-11", category:.genesis, propheticMeaning:"A circuncisão física aponta para a circuncisão do coração (Rm 2:29), realizada espiritualmente pelo Espírito Santo na conversão. Cristo é o cumprimento de toda a lei cerimonial."),
    QuizQuestion(id:33, question:"Quantos anos tinha Abraão quando Isaque nasceu?", options:["80 anos","100 anos","90 anos","110 anos"], correctIndex:1, explanation:"Abraão tinha 100 anos quando Isaque nasceu, e Sara tinha 90 anos, cumprindo a promessa sobrenatural de Deus.", reference:"Gênesis 21:5", category:.genesis, propheticMeaning:"O nascimento de Isaque de um ventre morto e um pai centenário aponta para a ressurreição — o poder de Deus que dá vida onde humanamente é impossível. Paulo usa isso como tipo da fé (Rm 4:19)."),
    QuizQuestion(id:34, question:"Qual cidade pecaminosa Deus destruiu no tempo de Abraão?", options:["Nínive e Babilônia","Jericó e Ai","Sodoma e Gomorra","Tiro e Sidom"], correctIndex:2, explanation:"Deus destruiu Sodoma e Gomorra com fogo e enxofre por causa de seus pecados, mas salvou Lot e suas filhas.", reference:"Gênesis 19:24-25", category:.genesis, propheticMeaning:"A destruição de Sodoma é usada em todo o NT como tipo do juízo final (Lc 17:29; Jd 7). Assim como Lot foi tirado antes do fogo, os salvos em Cristo serão livrados do juízo vindouro."),
    QuizQuestion(id:35, question:"O que aconteceu com a esposa de Lot ao fugir de Sodoma?", options:["Foi salva junto com Lot","Foi levada pelos anjos","Morreu de medo","Virou estátua de sal ao"], correctIndex:3, explanation:"A esposa de Lot olhou para trás ao fugir de Sodoma, desobedecendo à ordem dos anjos, e tornou-se uma estátua de sal.", reference:"Gênesis 19:26", category:.genesis, propheticMeaning:"Jesus citou esse episódio para advertir sobre a tentação de olhar para trás ao ouvir o chamado do evangelho. 'Lembrai-vos da mulher de Lot' (Lc 17:32) — o apego ao mundo mata espiritualmente."),
    QuizQuestion(id:36, question:"Qual foi o maior teste que Deus impôs a Abraão?", options:["Oferecer Isaque em sacrifício","Deixar sua terra natal","Enfrentar quatro reis","Fazer aliança com Abimeleque"], correctIndex:0, explanation:"Deus ordenou que Abraão oferecesse seu filho Isaque como holocausto no monte Moriá. Abraão obedeceu, mas Deus providenciou um carneiro como substituto.", reference:"Gênesis 22:1-14", category:.genesis, propheticMeaning:"Este é o tipo mais claro do sacrifício de Cristo: o pai oferece o filho único e amado, no monte Moriá (onde depois ficaria o templo), e Deus provê o substituto. O carneiro preso pelos chifres = Cristo coroado de espinhos."),
    QuizQuestion(id:37, question:"Qual o nome do lugar onde Abraão ia sacrificar Isaque?", options:["Monte Sinai","Monte Moriá","Monte Carmelo","Monte Nebo"], correctIndex:1, explanation:"Deus ordenou que Abraão fosse ao monte Moriá, que mais tarde seria o local onde Salomão construiu o templo em Jerusalém.", reference:"Gênesis 22:2; 2 Crônicas 3:1", category:.genesis, propheticMeaning:"O monte Moriá onde Abraão ofereceu Isaque é o mesmo local do templo e, segundo a tradição, próximo ao Calvário, onde Jesus foi crucificado. A geografia confirma o tipo profético."),
    QuizQuestion(id:38, question:"O que Abraão disse a Isaque quando este perguntou onde estava o animal para o sacrifício?", options:["'Não te preocupes, filho'","'Nós voltaremos logo'","'Deus proverá para si o","'O Senhor nos guiará'"], correctIndex:2, explanation:"Abraão respondeu profeticamente: 'Deus proverá para si o cordeiro para o holocausto, meu filho.' Isso se cumpriu naquele momento e profeticamente em Cristo.", reference:"Gênesis 22:8", category:.genesis, propheticMeaning:"'Deus proverá o cordeiro' é uma das mais belas profecias do AT. João Batista identificou Jesus como 'o Cordeiro de Deus que tira o pecado do mundo' (Jo 1:29), cumprindo a profecia de Abraão."),
    QuizQuestion(id:39, question:"Como se chamavam os filhos de Isaque?", options:["Caim e Abel","Isaque e Ismael","Rúben e Simeão","Jacó e Esaú"], correctIndex:3, explanation:"Isaque teve gêmeos com Rebeca: Esaú, o primogênito, e Jacó, o segundo, que nasceu segurando o calcanhar do irmão.", reference:"Gênesis 25:24-26", category:.genesis, propheticMeaning:"Jacó e Esaú ilustram a soberania da eleição divina: 'o maior servirá ao menor' antes de nascerem mostra que a eleição não é por obras mas por aquele que chama (Rm 9:11-13)."),
    QuizQuestion(id:40, question:"O que Esaú trocou com Jacó por um prato de lentilhas?", options:["Seu direito de","Suas ovelhas","Sua bênção","Sua espada"], correctIndex:0, explanation:"Esaú, morto de fome ao chegar do campo, trocou seu direito de primogenitura pelo prato de ensopado de lentilhas que Jacó preparara.", reference:"Gênesis 25:29-34", category:.genesis, propheticMeaning:"Esaú vendendo sua primogenitura por comida ilustra quem troca as bênçãos eternas por satisfações temporais. Hebreus 12:16 usa Esaú como advertência contra a mundanidade e profanidade."),
    QuizQuestion(id:41, question:"Qual era o nome da esposa de Isaque?", options:["Sara","Rebeca","Raquel","Lea"], correctIndex:1, explanation:"Rebeca foi escolhida por Eliezer, servo de Abraão, para ser esposa de Isaque, após uma busca orientada por Deus.", reference:"Gênesis 24:67", category:.genesis, propheticMeaning:"A busca de Eliezer por uma noiva para Isaque é tipo do Espírito Santo (enviado pelo Pai) que busca e chama a Igreja para ser noiva de Cristo, o Filho."),
    QuizQuestion(id:42, question:"O que Jacó viu em sonho em Betel?", options:["Um mar de fogo","Um grande templo","Uma escada que chegava ao","Um leão e um cordeiro"], correctIndex:2, explanation:"Jacó sonhou com uma escada que ia da terra ao céu, com anjos subindo e descendo, e Deus falando do alto, renovando a aliança abraâmica.", reference:"Gênesis 28:12", category:.genesis, propheticMeaning:"Jesus referiu-se a essa visão em João 1:51, dizendo que ele mesmo é a escada — o único mediador entre Deus e os homens (1 Tm 2:5), por quem os anjos ministram e as orações sobem."),
    QuizQuestion(id:43, question:"Por quantos anos Jacó trabalhou para casar com Raquel?", options:["7 anos","21 anos","3 anos","14 anos"], correctIndex:3, explanation:"Jacó trabalhou 7 anos por Raquel, mas Labão o enganou dando-lhe Lea. Então trabalhou mais 7 anos por Raquel — 14 anos no total.", reference:"Gênesis 29:18-28", category:.genesis, propheticMeaning:"Os 14 anos de serviço de Jacó por Raquel ilustram o amor redentor que paga um alto preço pela amada. Cristo pagou o preço supremo por sua Igreja, amando-a antes mesmo de ela o amar."),
    QuizQuestion(id:44, question:"Com qual nome Deus renomeou Jacó após a luta com o anjo?", options:["Israel","Ismael","Judá","Efraim"], correctIndex:0, explanation:"Após lutar toda a noite com um ser divino e prevalecer, Jacó recebeu o nome Israel, que significa 'o que luta com Deus'.", reference:"Gênesis 32:28", category:.genesis, propheticMeaning:"A luta de Jacó com Deus é tipo da oração persistente e da luta da fé. O crente que, como Jacó, se aferra a Deus e não o deixa ir sem bênção, recebe nova identidade e propósito divino."),
    QuizQuestion(id:45, question:"Quantos filhos teve Jacó, que deram origem às 12 tribos de Israel?", options:["10","12","11","13"], correctIndex:1, explanation:"Jacó teve 12 filhos: Rúben, Simeão, Levi, Judá, Issacar, Zebulom, Dã, Naftali, Gade, Aser, José e Benjamim.", reference:"Gênesis 35:22-26", category:.genesis, propheticMeaning:"Os 12 filhos de Jacó = 12 tribos de Israel = 12 apóstolos de Cristo = 12 fundamentos da Nova Jerusalém (Ap 21). O número 12 representa o povo de Deus em sua plenitude governamental."),
    QuizQuestion(id:46, question:"Por que os irmãos de José o odiavam?", options:["Porque ele era preguiçoso","Porque ele roubava deles","Porque seu pai o amava mais e","Porque ele era mais forte"], correctIndex:2, explanation:"Israel amava José mais do que os outros filhos por ser filho da sua velhice, e lhe fez uma túnica de muitas cores, causando inveja nos irmãos.", reference:"Gênesis 37:3-4", category:.genesis, propheticMeaning:"José é o tipo mais completo de Cristo no AT: amado pelo pai, rejeitado pelos irmãos, vendido, falsamente acusado, exaltado, e por fim salvando os que o rejeitaram — tudo aponta para Jesus."),
    QuizQuestion(id:47, question:"Por quantas moedas de prata José foi vendido pelos irmãos?", options:["10","30","50","20"], correctIndex:3, explanation:"Os irmãos de José o venderam a mercadores ismaelitas por 20 moedas de prata, que o levaram ao Egito.", reference:"Gênesis 37:28", category:.genesis, propheticMeaning:"José vendido por 20 moedas prefigura Jesus vendido por 30 moedas (Judas). Ambos foram entregues por seus irmãos/amigos íntimos, sofreram injustamente e foram exaltados após a humilhação."),
    QuizQuestion(id:48, question:"O que aconteceu com José no Egito após ser vendido?", options:["Serviu na casa de Potifar","Tornou-se imediatamente governador","Foi colocado na prisão diretamente","Fugiu para o deserto"], correctIndex:0, explanation:"José foi comprado por Potifar, oficial do Faraó, e serviu em sua casa com excelência até que a esposa de Potifar o acusou falsamente.", reference:"Gênesis 39:1-2", category:.genesis, propheticMeaning:"O Senhor estava com José em tudo (Gn 39:2,21). Da mesma forma, a presença de Deus acompanha seus servos mesmo nas situações mais adversas, transformando sofrimento em propósito divino."),
    QuizQuestion(id:49, question:"Como José interpretava eventos especiais que outros não conseguiam entender?", options:["Lia o futuro nas estrelas","Interpretava sonhos com","Consultava sacerdotes","Usava o Urim e Tumim"], correctIndex:1, explanation:"José tinha o dom de interpretar sonhos concedido por Deus, o que eventualmente o levou perante o Faraó para interpretar seus sonhos sobre as sete vacas e as sete espigas.", reference:"Gênesis 41:16", category:.genesis, propheticMeaning:"José reconhecia que as interpretações pertencem a Deus (Gn 40:8), tipo de Jesus que revelava os mistérios do Pai. A sabedoria divina exaltada em meio ao sofrimento é padrão messiânico."),
    QuizQuestion(id:50, question:"Qual cargo José recebeu no Egito após interpretar o sonho do Faraó?", options:["Chefe do exército","Sumo sacerdote","Governador do Egito","Intendente do palácio"], correctIndex:2, explanation:"Faraó ficou tão impressionado com a sabedoria de José que o colocou como governador de todo o Egito, segundo apenas ao próprio Faraó.", reference:"Gênesis 41:40-41", category:.genesis, propheticMeaning:"José exaltado da prisão ao trono do Egito prefigura a ressurreição e exaltação de Cristo: humilhado até a morte na cruz, exaltado ao lugar mais alto, com todo poder no céu e na terra (Fp 2:9-11)."),
    QuizQuestion(id:51, question:"Quantos anos de abundância e fome José previu no sonho do Faraó?", options:["5 de abundância e 5 de fome","10 de abundância e 3 de fome","3 de abundância e 7 de fome","7 de abundância e 7 de fome"], correctIndex:3, explanation:"Os 7 anos de abundância seguidos de 7 anos de fome levaram José a armazenar alimentos durante a abundância para salvar o Egito e as nações durante a escassez.", reference:"Gênesis 41:29-30", category:.genesis, propheticMeaning:"José preparando provisão durante a abundância para o tempo de fome é tipo de Cristo que provê salvação eterna enquanto há tempo — a graça oferecida agora prepara os fiéis para o julgamento vindouro."),
    QuizQuestion(id:52, question:"Quantos irmãos de José vieram ao Egito buscar mantimentos na fome?", options:["10","9","11","12"], correctIndex:0, explanation:"Dez irmãos de José vieram ao Egito, pois Jacó não deixou Benjamim ir com eles por temer que lhe acontecesse algo.", reference:"Gênesis 42:3-4", category:.genesis, propheticMeaning:"Os irmãos que rejeitaram José precisando agora da graça dele é tipo de Israel (que rejeitou Jesus) que ao final precisará reconhecê-lo como Messias e Salvador (Zc 12:10; Rm 11:26)."),
    QuizQuestion(id:53, question:"Como José se revelou a seus irmãos?", options:["Mostrando a túnica que haviam rasgado","Chorando e dizendo 'Eu sou José","Por meio de um intérprete","Através de uma carta"], correctIndex:1, explanation:"José não se pôde mais conter e chorou alto, revelando-se a seus irmãos: 'Eu sou José! Vive ainda meu pai?'", reference:"Gênesis 45:3", category:.genesis, propheticMeaning:"A revelação de José a seus irmãos com choro e reconciliação prefigura a revelação de Cristo a Israel no fim dos tempos (Zc 12:10), quando a nação verá aquele que traspassou e se lamentará."),
    QuizQuestion(id:54, question:"O que José disse aos irmãos sobre sua venda para o Egito?", options:["'Vocês planejaram o mal contra mim","'Fui punido por Deus por causa de vocês'","'Deus o enviou antes de vós para...","'Nunca vos perdoarei'"], correctIndex:2, explanation:"José reconheceu a soberania de Deus: apesar da maldade dos irmãos, Deus tinha um plano maior de preservar vidas, inclusive a deles.", reference:"Gênesis 45:5-7", category:.genesis, propheticMeaning:"José vendo a providência de Deus no sofrimento prefigura Cristo que, na cruz, foi traído pelos homens mas cumpriu o eterno propósito de Deus para salvar a humanidade (At 2:23)."),
    QuizQuestion(id:55, question:"Onde Jacó e toda a sua família foram morar no Egito a convite de José?", options:["Alexandria","Menfis","Ramessés","Gessen"], correctIndex:3, explanation:"Faraó ordenou que José colocasse seu pai e irmãos na terra de Gessen, a melhor terra do Egito, para que ficassem perto dele.", reference:"Gênesis 45:10", category:.genesis, propheticMeaning:"Israel descendo ao Egito é parte do plano de Deus para formar uma nação. Quatro séculos depois, o Êxodo revelaria o poder redentor de Deus, prefigurando a redenção em Cristo."),
    QuizQuestion(id:56, question:"Qual foi a bênção especial de Jacó que ele deu ao filho Judá?", options:["Que o cetro não se apartaria de Judá","Que seria o mais rico","Que teria mais filhos que todos...","Que viveria mais que todos os irmãos"], correctIndex:0, explanation:"Jacó profetizou que o cetro não se apartaria de Judá até que viesse Siló (o Messias), a quem os povos obedeceriam.", reference:"Gênesis 49:10", category:.genesis, propheticMeaning:"Esta é uma das profecias messiânicas mais claras do AT. 'Siló' é entendido como referência ao Messias que viria da tribo de Judá — Jesus Cristo, o Leão da tribo de Judá (Ap 5:5), Rei eterno."),
    QuizQuestion(id:57, question:"Qual era a profissão dos patriarcas hebreus antes do Êxodo?", options:["Agricultores","Pastores","Guerreiros","Pescadores"], correctIndex:1, explanation:"Abraão, Isaque, Jacó e seus filhos eram pastores nômades que criavam ovelhas e gado, uma cultura radicalmente diferente dos egípcios sedentários.", reference:"Gênesis 47:3", category:.genesis, propheticMeaning:"Os patriarcas como pastores prefiguram Cristo, o Bom Pastor (Jo 10:11), e os crentes como ovelhas sob seu cuidado. O pastor que cuida e sacrifica tudo pelas ovelhas é o padrão messiânico."),
    QuizQuestion(id:58, question:"Qual era o significado do nome 'Israel' dado a Jacó?", options:["'Amado de Deus'","'Filho da promessa'","'Que luta com Deus' ou","'Herdeiro das nações'"], correctIndex:2, explanation:"Israel significa 'o que luta com Deus' ou 'príncipe com Deus', dado após Jacó lutar com o anjo e prevalecer.", reference:"Gênesis 32:28", category:.genesis, propheticMeaning:"O nome Israel descreve o povo de Deus como aquele que luta em oração e fé. A Igreja herdou essa característica — somos chamados a prevalecer na fé e na oração até receber a bênção de Deus."),
    QuizQuestion(id:59, question:"Qual profecia José fez em seu leito de morte sobre os ossos dele?", options:["Que seriam enterrados no Egito","Que seriam jogados no rio Nilo","Que seriam colocados em uma pirâmide","Que Deus visitaria os filhos de Israel"], correctIndex:3, explanation:"José pediu que ao partirem do Egito levassem seus ossos consigo para a terra prometida, demonstrando fé na promessa de Deus.", reference:"Gênesis 50:24-25", category:.genesis, propheticMeaning:"A fé de José na ressurreição e no retorno à terra prometida é tipo da esperança cristã. Hebreus 11:22 cita isso como ato de fé: crer nas promessas de Deus mesmo além da morte."),
    QuizQuestion(id:60, question:"Qual a última palavra registrada de Gênesis sobre José?", options:["Que ele morreu aos 110 anos e foi","Que ele morreu triste e solitário","Que ele voltou à terra de Canaã","Que ele foi enterrado ao lado de seu pai"], correctIndex:0, explanation:"José morreu aos 110 anos, foi embalsamado e colocado em um caixão no Egito, aguardando ser levado para a terra prometida.", reference:"Gênesis 50:26", category:.genesis, propheticMeaning:"José embalsamado esperando o Êxodo é como a promessa que aguarda cumprimento. Moisés levou seus ossos no Êxodo (Ex 13:19), e foram finalmente sepultados em Siquém (Js 24:32) — a fé sempre é honrada."),
    // JESUS E EVANGELHOS (61-167)
    QuizQuestion(id:61, question:"Em qual cidade Jesus nasceu?", options:["Nazaré","Belém","Jerusalém","Jericó"], correctIndex:1, explanation:"Jesus nasceu em Belém da Judeia, cumprindo a profecia de Miquéias 5:2, pois José e Maria viajaram para o recenseamento.", reference:"Lucas 2:4-7; Miquéias 5:2", category:.jesus, propheticMeaning:"Miquéias 5:2 profetizou 700 anos antes que o Governador de Israel nasceria em Belém Efrata. O nascimento de Jesus nesse local específico confirma que ele é o Messias prometido."),
    QuizQuestion(id:62, question:"Quem anunciou a Maria que ela conceberia o Filho de Deus?", options:["O anjo Miguel","João Batista","O anjo Gabriel","O profeta Simeão"], correctIndex:2, explanation:"O anjo Gabriel foi enviado por Deus a Nazaré para anunciar a Maria que ela conceberia e daria à luz o Filho do Altíssimo pelo Espírito Santo.", reference:"Lucas 1:26-31", category:.jesus, propheticMeaning:"Gabriel ('Deus é minha força') anunciou o nascimento de Jesus como cumpriu Isaías 7:14: 'Uma virgem conceberá e dará à luz um filho, e chamarão o seu nome Emanuel', que significa 'Deus conosco'."),
    QuizQuestion(id:63, question:"Quem batizou Jesus no rio Jordão?", options:["Pedro","Paulo","Elias","João Batist"], correctIndex:3, explanation:"João Batista batizou Jesus no Jordão. Ao sair da água, o Espírito desceu como pomba e uma voz do céu disse: 'Este é meu Filho amado'.", reference:"Mateus 3:13-17", category:.jesus, propheticMeaning:"O batismo de Jesus foi sua unção como Profeta, Sacerdote e Rei. O Pai fala, o Filho é ungido, o Espírito desce — a Trindade se manifesta, inaugurando o ministério do Messias."),
    QuizQuestion(id:64, question:"Quantos dias Jesus jejuou no deserto antes de ser tentado pelo diabo?", options:["40","20","30","50"], correctIndex:0, explanation:"Jesus foi levado pelo Espírito ao deserto onde jejuou quarenta dias e quarenta noites, sendo então tentado pelo diabo.", reference:"Mateus 4:1-2", category:.jesus, propheticMeaning:"Os 40 dias de Jesus no deserto ecoam os 40 anos de Israel no deserto. Onde Israel falhou em cada tentação, Jesus venceu, cumprindo o que Israel deveria ter sido — o servo obediente de Deus."),
    QuizQuestion(id:65, question:"Com quais palavras Jesus respondeu cada tentação do diabo no deserto?", options:["'Vai-te, Satanás'","'Escrito está'","'Não farei isso'","'Senhor, me ajuda'"], correctIndex:1, explanation:"Jesus respondeu às três tentações com 'Escrito está', citando Deuteronômio, mostrando que a Palavra de Deus é a arma suprema contra o tentador.", reference:"Mateus 4:4,7,10", category:.jesus, propheticMeaning:"Jesus usando Deuteronômio para vencer Satanás mostra que a Palavra de Deus é a espada do Espírito (Ef 6:17). O segundo Adão venceu onde o primeiro falhou, não apenas com força, mas com a Palavra."),
    QuizQuestion(id:66, question:"Quais foram os primeiros discípulos chamados por Jesus?", options:["Pedro e Paulo","Tiago e João","Pedro e André","Mateus e Lucas"], correctIndex:2, explanation:"Pedro e André foram os primeiros discípulos chamados. Jesus os encontrou lançando redes no mar e disse: 'Vinde após mim e eu vos farei pescadores de homens'.", reference:"Mateus 4:18-19", category:.jesus, propheticMeaning:"Pescadores se tornando pescadores de homens é a chamada apostólica: o evangelho lança a rede do amor de Deus para trazer almas para o reino. Jesus usa pessoas comuns para obra extraordinária."),
    QuizQuestion(id:67, question:"Qual foi o primeiro milagre de Jesus?", options:["Caminhar sobre as águas","Multiplicar pães e peixes","Ressuscitar Lázaro","Transformar água em vinho"], correctIndex:3, explanation:"O primeiro milagre de Jesus foi transformar água em vinho em Caná da Galileia, a pedido de sua mãe Maria, num casamento.", reference:"João 2:1-11", category:.jesus, propheticMeaning:"A transformação da água (purificação ritual judaica) em vinho (alegria do novo pacto) sinaliza que Jesus veio substituir o sistema religioso antigo pela graça e alegria do evangelho."),
    QuizQuestion(id:68, question:"Quantos pães e peixes Jesus usou para alimentar 5.000 homens?", options:["5 pães e 2 peixes","3 pães e 2 peixes","7 pães e 3 peixes","10 pães e 5 peixes"], correctIndex:0, explanation:"Cinco pães e dois peixes foram abençoados por Jesus e multiplicados para alimentar 5.000 homens além de mulheres e crianças, sobrando 12 cestos.", reference:"Mateus 14:17-21", category:.jesus, propheticMeaning:"Jesus alimentando a multidão ecoa Moisés e o maná no deserto. Mas Jesus é o verdadeiro Pão do Céu (Jo 6:35) — não apenas supre o corpo, mas satisfaz a alma para a vida eterna."),
    QuizQuestion(id:69, question:"Qual versículo fala do amor de Deus ao mundo inteiro?", options:["João 1:1","João 3:16","Romanos 8:28","Salmos 23:1"], correctIndex:1, explanation:"'Porque Deus tanto amou o mundo que deu o seu Filho Unigênito, para que todo o que nele crê não pereça, mas tenha a vida eterna.'", reference:"João 3:16", category:.jesus, propheticMeaning:"João 3:16 é o resumo do evangelho: o amor eterno de Deus (o Pai), manifesto no dom supremo (o Filho), recebido pela fé (crer), resultando em vida eterna — a salvação total em uma sentença."),
    QuizQuestion(id:70, question:"Quem traiu Jesus por 30 moedas de prata?", options:["Pedro","Tomé","Judas Iscari","Filipe"], correctIndex:2, explanation:"Judas Iscariotes, um dos doze, traiu Jesus pelos sumo-sacerdotes por 30 moedas de prata, conforme profetizado por Zacarias.", reference:"Mateus 26:14-16; Zacarias 11:12", category:.jesus, propheticMeaning:"Zacarias 11:12-13 profetizou 500 anos antes o preço exato de 30 moedas de prata e que o dinheiro seria jogado no templo e dado ao oleiro. Isso foi cumprido ponto por ponto com Judas e o campo do oleiro."),
    QuizQuestion(id:71, question:"Em qual dia da semana Jesus ressuscitou?", options:["Sexta-feira","Sábado","Segunda-feira","Domingo"], correctIndex:3, explanation:"Jesus ressuscitou no primeiro dia da semana (domingo), enquanto ainda estava escuro, e apareceu primeiro a Maria Madalena.", reference:"João 20:1; Marcos 16:9", category:.jesus, propheticMeaning:"A ressurreição no primeiro dia — o oitavo dia da semana — inaugura a nova criação. Assim como Deus criou no primeiro dia, Cristo ressurge no primeiro dia, iniciando a nova criação em Espírito."),
    QuizQuestion(id:72, question:"Quantos dias Jesus ficou na terra após a ressurreição antes de ascender?", options:["40 dias","3 dias","7 dias","50 dias"], correctIndex:0, explanation:"Jesus apareceu a seus discípulos durante 40 dias após a ressurreição, ensinando sobre o Reino de Deus, antes de ascender ao céu.", reference:"Atos 1:3", category:.jesus, propheticMeaning:"Os 40 dias de aparições pós-ressurreição estabelecem a realidade histórica da ressurreição (mais de 500 testemunhas, 1 Co 15:6) e completam o ensino do Reino antes da descida do Espírito no Pentecostes."),
    QuizQuestion(id:73, question:"Qual das bem-aventuranças diz 'bem-aventurados os misericordiosos'?", options:["Os que choram receberão consolo","Os misericordiosos alcançarão misericórdia","Os pacificadores serão chamados filhos de...","Os puros de coração verão a Deus"], correctIndex:1, explanation:"'Bem-aventurados os misericordiosos, porque eles alcançarão misericórdia.' Jesus chama seus seguidores a tratar os outros com a mesma graça que recebem de Deus.", reference:"Mateus 5:7", category:.jesus, propheticMeaning:"A misericórdia é o caráter central de Deus (Êx 34:6). As bem-aventuranças descrevem o caráter do cidadão do Reino — aquele transformado pela graça de Cristo se torna canal dessa mesma graça."),
    QuizQuestion(id:74, question:"Qual parábolaa Jesus contou sobre um filho que gastou toda a herança e voltou ao pai?", options:["Parábola do semeador","Parábola do bom samaritano","Parábola do filho pródigo","Parábola das dez virgens"], correctIndex:2, explanation:"Na parábola do filho pródigo, um filho pediu sua herança, desperdiçou tudo, voltou arrependido ao pai, que o recebeu com festa e alegria.", reference:"Lucas 15:11-32", category:.jesus, propheticMeaning:"O pai correndo ao encontro do filho que voltou é a mais bela imagem do amor do Pai celestial por pecadores arrependidos. A festa representa o gozo do céu por um pecador que se arrepende (Lc 15:10)."),
    QuizQuestion(id:75, question:"Na parábola do Bom Samaritano, o que o samaritano fez pelo homem ferido?", options:["Passou ao largo como os outros","Chamou as autoridades","Apenas orou por ele","Cuidou dele"], correctIndex:3, explanation:"O samaritano, desprezado pelos judeus, teve compaixão: tratou as feridas, montou o homem no seu animal, levou-o à hospedaria e pagou por seus cuidados.", reference:"Lucas 10:33-35", category:.jesus, propheticMeaning:"Jesus é o verdadeiro Bom Samaritano — vindo do lugar desprezado (Nazaré), cuida do homem caído no pecado, paga o preço com seu sangue e confia à Igreja (a estalagem) o cuidado dos redimidos."),
    QuizQuestion(id:76, question:"Qual milagre de Jesus demonstrou seu poder sobre a morte?", options:["Ressuscitar Lázaro","Andar sobre as águas","Curar o cego de nascença","Multiplicar os pães"], correctIndex:0, explanation:"Jesus ressuscitou Lázaro quatro dias após sua morte, declarando: 'Eu sou a ressurreição e a vida.' Foi o maior sinal de seu poder divino antes da própria ressurreição.", reference:"João 11:43-44", category:.jesus, propheticMeaning:"Lázaro ressuscitado após 4 dias (quando o judeu acreditava que a alma já partira definitivamente) demonstra que Jesus tem poder absoluto sobre a morte, prefigurando a ressurreição geral no último dia."),
    QuizQuestion(id:77, question:"O que Jesus fez ao entrar em Jerusalém na Semana Santa?", options:["Chegou a pé em silêncio","Entrou montado num jumentinho","Entrou num carro de guerra","Chegou numa barca pelo rio"], correctIndex:1, explanation:"Jesus entrou em Jerusalém montado num jumentinho, enquanto o povo estendeu mantos no caminho e agitou ramos de palmeira, clamando 'Hosana ao Filho de Davi!'", reference:"Mateus 21:1-9; Zacarias 9:9", category:.jesus, propheticMeaning:"Zacarias 9:9 profetizou 500 anos antes: 'Eis que o teu Rei vem a ti, humilde e montado num jumento.' A entrada triunfal cumpre a profecia e proclama Jesus como o Rei-Messias de Israel."),
    QuizQuestion(id:78, question:"O que Jesus instituiu na última ceia?", options:["O batismo","A oração do Pai Nosso","A Ceia do Senhor","A dízima"], correctIndex:2, explanation:"Na última ceia com seus discípulos, Jesus tomou o pão e o cálice, declarando que eram seu corpo e seu sangue da nova aliança, ordenando que o fizessem em memória dele.", reference:"Lucas 22:19-20", category:.jesus, propheticMeaning:"A Ceia do Senhor substituiu a Páscoa judaica. O cordeiro pascal = Jesus; o sangue nos umbrais = seu sangue que nos protege do juízo. Jesus é o verdadeiro Cordeiro Pascal (1 Co 5:7)."),
    QuizQuestion(id:79, question:"Em qual jardim Jesus orou com angústia antes de ser preso?", options:["Jardim do Éden","Jardim de José de Arimateia","Jardim dos Cedros","Jardim de Getsêmani"], correctIndex:3, explanation:"No jardim de Getsêmani, Jesus orou com tanto fervor que seu suor era como gotas de sangue, pedindo que o cálice passasse, mas submetendo-se à vontade do Pai.", reference:"Lucas 22:42-44", category:.jesus, propheticMeaning:"Em Getsêmani Jesus enfrentou a batalha espiritual suprema. Onde Adão caiu num jardim (Éden), Jesus venceu num jardim (Getsêmani). Onde o primeiro Adão desobedeceu, o segundo obedeceu até à morte."),
    QuizQuestion(id:80, question:"Quem era o governador romano que condenou Jesus à morte?", options:["Pôncio Pilatos","Herodes Antipas","César Augusto","Tibério César"], correctIndex:0, explanation:"Pôncio Pilatos, governador romano da Judeia, condenou Jesus à crucificação apesar de não encontrar nele nenhuma culpa.", reference:"João 19:16", category:.jesus, propheticMeaning:"A condenação de Jesus pelo tribunal romano e judeu cumpre a profecia de que o Messias seria entregue aos gentios (Lc 18:32) e rejeitado por Israel (Is 53:3), para que a salvação viesse a todos os povos."),
    QuizQuestion(id:81, question:"Quais foram as últimas palavras de Jesus na cruz segundo Lucas?", options:["'Meu Deus, meu Deus","'Pai, nas tuas mãos","'Está consumado!'","'Tenho sede'"], correctIndex:1, explanation:"Lucas registra as últimas palavras de Jesus: 'Pai, nas tuas mãos entrego o meu espírito', citando o Salmo 31:5, em um ato de confiança total ao Pai.", reference:"Lucas 23:46", category:.jesus, propheticMeaning:"Jesus entregando seu espírito voluntariamente ao Pai mostra que ninguém tirou sua vida — ele a entregou (Jo 10:18). Sua morte foi o ato supremo de obediência e amor, cumprindo o plano eterno de redenção."),
    QuizQuestion(id:82, question:"O que aconteceu no templo quando Jesus morreu na cruz?", options:["O templo desabou","Um fogo consumiu o altar","O véu do templo rasgou-se de","Os sacerdotes fugiram"], correctIndex:2, explanation:"No momento da morte de Jesus, o véu do templo rasgou-se de cima a baixo, abrindo o acesso ao Santo dos Santos que antes era restrito ao sumo-sacerdote.", reference:"Mateus 27:51", category:.jesus, propheticMeaning:"O véu rasgado de cima a baixo (por Deus, não por homem) declara que o acesso direto ao Pai está aberto a todos pela morte de Cristo. Hebreus 10:20 confirma: o véu rasgado é o corpo de Cristo."),
    QuizQuestion(id:83, question:"Quem providenciou o sepulcro onde Jesus foi enterrado?", options:["Pedro","Nicodemos","João","José de Arimate"], correctIndex:3, explanation:"José de Arimateia, membro do Sinédrio e discípulo secreto de Jesus, pediu a Pilatos o corpo de Jesus e o sepultou em seu próprio sepulcro novo.", reference:"Mateus 27:57-60", category:.jesus, propheticMeaning:"Isaías 53:9 profetizou que o Messias faria 'a sua sepultura com os ricos'. José de Arimateia, homem rico, cumpriu isso séculos depois, confirmando a precisão profética das Escrituras."),
    QuizQuestion(id:84, question:"Quem foi a primeira pessoa a ver Jesus ressuscitado?", options:["Maria Madalena","Pedro","João","A mãe de Jesus"], correctIndex:0, explanation:"Maria Madalena foi a primeira a ver Jesus ressurreto, na manhã do domingo de Páscoa, junto ao sepulcro vazio.", reference:"João 20:14-16", category:.jesus, propheticMeaning:"Jesus escolhendo revelar-se primeiro a uma mulher (considerada testemunha inválida na lei romana e judaica) mostra que o evangelho inverte os valores do mundo: os últimos serão primeiros no Reino de Deus."),
    QuizQuestion(id:85, question:"O que Jesus disse a Tomé, que duvidava da ressurreição?", options:["'Vai embora, incrédulo'","'Vê minhas mãos e meu lado","'Você precisará acreditar sem ver'","'Tomé, tu me decepciona'"], correctIndex:1, explanation:"Jesus apareceu a Tomé e disse que tocasse suas mãos e seu lado, concluindo: 'Não sejas incrédulo, mas crente.' Tomé respondeu: 'Senhor meu e Deus meu!'", reference:"João 20:27-28", category:.jesus, propheticMeaning:"A confissão de Tomé 'Senhor meu e Deus meu' é a afirmação mais clara da divindade de Jesus nos evangelhos. Jesus aceita a adoração, confirmando que é Deus encarnado, não apenas um profeta."),
    QuizQuestion(id:86, question:"O que Jesus disse ser o maior mandamento?", options:["Guardar o sábado","Honrar pai e mãe","Amar a Deus de todo o","Não matar"], correctIndex:2, explanation:"Jesus respondeu que o maior mandamento é amar a Deus de todo o coração, alma e mente, e o segundo semelhante é amar o próximo como a si mesmo.", reference:"Mateus 22:37-39", category:.jesus, propheticMeaning:"Os dois grandes mandamentos resumem toda a lei: amor vertical (Deus) e horizontal (próximo). Cristo os cumpriu perfeitamente e nos capacita pelo Espírito a vivê-los (Rm 13:10)."),
    QuizQuestion(id:87, question:"O que Jesus disse sobre si mesmo em João 14:6?", options:["'Eu sou a porta'","'Eu sou a videira verdadeira'","'Eu sou o Bom Pastor'","'Eu sou o caminho"], correctIndex:3, explanation:"Jesus declarou: 'Eu sou o caminho, a verdade e a vida; ninguém vem ao Pai senão por mim', afirmando ser o único mediador entre Deus e os homens.", reference:"João 14:6", category:.jesus, propheticMeaning:"'Eu sou o caminho' — Jesus não aponta o caminho, ele É o caminho. Esta declaração exclusivista confirma que a salvação é somente em Cristo, cumprindo Atos 4:12: 'não há em nenhum outro salvação'."),
    QuizQuestion(id:88, question:"Qual discípulo negou Jesus três vezes?", options:["Pedro","João","Tiago","André"], correctIndex:0, explanation:"Pedro, apesar de jurar que nunca negaria Jesus, negou-o três vezes na noite em que ele foi preso, antes de o galo cantar.", reference:"Mateus 26:69-75", category:.jesus, propheticMeaning:"A restauração de Pedro após a negação (Jo 21:15-17) mostra que o fracasso não é o fim para quem se arrepende. Jesus perguntou três vezes 'Você me ama?' — uma restauração para cada negação."),
    QuizQuestion(id:89, question:"Em qual monte Jesus proferiu o Sermão do Monte?", options:["Monte Sinai","Monte das","Monte Hermom","Monte das Oliveiras"], correctIndex:1, explanation:"O Sermão do Monte foi pregado numa colina da Galileia (tradição aponta a área do lago de Tiberíades), onde Jesus ensinou as bem-aventuranças e os princípios do Reino.", reference:"Mateus 5:1", category:.jesus, propheticMeaning:"Assim como Moisés recebeu a lei no Sinai, Jesus ensinou a lei do Reino numa montanha, mostrando ser maior que Moisés — não veio abolir a lei mas cumpri-la e internalizá-la no coração."),
    QuizQuestion(id:90, question:"O que Jesus fez com os vendedores e cambistas no templo?", options:["Pregou a eles","Os converteu","Os expulsou","Ignorou-os"], correctIndex:2, explanation:"Jesus expulsou os vendedores e cambistas do templo com um açoite de cordas, derrubando as mesas, dizendo que a casa de seu Pai havia sido transformada em covil de ladrões.", reference:"João 2:15-16", category:.jesus, propheticMeaning:"A limpeza do templo por Jesus cumpre o zelo de Salmos 69:9: 'O zelo da tua casa me consome.' Cristo é o verdadeiro templo de Deus (Jo 2:21) — ele purifica o lugar da presença divina."),
    QuizQuestion(id:91, question:"Qual é a oração que Jesus ensinou a seus discípulos, conhecida como Pai Nosso?", options:["João 3:16","Salmos 23","Lucas 11:1","Mateus 6:9-13"], correctIndex:3, explanation:"Jesus ensinou o Pai Nosso em Mateus 6:9-13 como modelo de oração: adoração ao Pai, pedido do Reino, provisão diária, perdão e livramento do mal.", reference:"Mateus 6:9-13", category:.jesus, propheticMeaning:"O Pai Nosso revela a natureza da oração cristã: começa com Deus (Pai, nome, reino, vontade) antes das necessidades humanas. Ensina que a relação filial com Deus é o fundamento de toda oração."),
    QuizQuestion(id:92, question:"Qual era a profissão de Mateus antes de seguir Jesus?", options:["Cobrador de","Pescador","Carpinteiro","Sacerdote"], correctIndex:0, explanation:"Mateus era cobrador de impostos (publicano), considerado traidor e pecador pelos judeus. Jesus o chamou da mesa de impostos para segui-lo.", reference:"Mateus 9:9", category:.jesus, propheticMeaning:"Jesus chamando um cobrador de impostos (desprezado por todos) mostra que o evangelho não é para os que se julgam justos, mas para os pecadores. 'Não vim chamar justos, mas pecadores' (Mt 9:13)."),
    QuizQuestion(id:93, question:"O que aconteceu no Monte da Transfiguração?", options:["Jesus ressuscitou","O rosto e vestes de Jesus","Jesus subiu ao céu","Um anjo lhe apareceu"], correctIndex:1, explanation:"Jesus se transfigurou diante de Pedro, Tiago e João: seu rosto brilhou como o sol, suas vestes ficaram brancas, e Moisés e Elias apareceram conversando com ele.", reference:"Mateus 17:1-3", category:.jesus, propheticMeaning:"A transfiguração revela a glória eterna de Cristo por trás da forma humana. Moisés (a Lei) e Elias (os Profetas) conversando com Jesus confirmam que toda a Escritura aponta para ele e se cumpre nele."),
    QuizQuestion(id:94, question:"Quem era Nicodemos e por que foi a Jesus de noite?", options:["Um pescador que tinha vergonha","Um sacerdote que queria arrestá-lo","Um fariseu e líder judeu que foi","Um gentio curioso"], correctIndex:2, explanation:"Nicodemos era fariseu e membro do Sinédrio. Foi a Jesus de noite, provavelmente para evitar críticas de seus pares, e Jesus lhe ensinou sobre o novo nascimento.", reference:"João 3:1-2", category:.jesus, propheticMeaning:"A conversa com Nicodemos introduz o novo nascimento (Jo 3:3-8) — nascido do Espírito. Nicodemos representa aqueles que têm religião mas precisam de uma transformação espiritual genuína."),
    QuizQuestion(id:95, question:"Qual mulher ungiu os pés de Jesus com perfume caro pouco antes de sua morte?", options:["Maria Madalena","Marta","Salomé","Maria de Betânia"], correctIndex:3, explanation:"Maria de Betânia ungiu os pés de Jesus com um perfume caríssimo (nardo puro) e os enxugou com seus cabelos, sendo criticada por Judas pelo 'desperdício'.", reference:"João 12:3", category:.jesus, propheticMeaning:"Jesus disse que Maria ungiu seu corpo para a sepultura (Mt 26:12). Inconscientemente, Maria realizou o rito de unção para morte e ressurreição. Sua devoção extravagante foi eternizada no evangelho (Mt 26:13)."),
    QuizQuestion(id:96, question:"O que Jesus declarou ser em João 6:35?", options:["O Pão da Vida","A Porta","O Bom Pastor","A Luz do Mundo"], correctIndex:0, explanation:"Jesus declarou: 'Eu sou o pão da vida; aquele que vem a mim não terá fome, e quem crer em mim não terá sede nunca.'", reference:"João 6:35", category:.jesus, propheticMeaning:"Assim como o maná alimentou Israel no deserto (tipo), Jesus, o verdadeiro pão do céu, alimenta espiritualmente para a vida eterna. Quem come esse pão viverá para sempre (Jo 6:51)."),
    QuizQuestion(id:97, question:"O que Jesus curou no homem da piscina de Betesda?", options:["Lepra","Paralisia","Cegueira","Surdez"], correctIndex:1, explanation:"Em Betesda, Jesus curou um homem paralítico que havia estado doente por 38 anos, ordenando: 'Levanta-te, toma o teu leito e anda.'", reference:"João 5:5-9", category:.jesus, propheticMeaning:"Os 38 anos de paralisia ecoam os 38 anos que Israel vagou no deserto sem progresso (Dt 2:14). Jesus vem curar a paralisia espiritual causada pelo pecado e nos dá capacidade de caminhar em novidade de vida."),
    QuizQuestion(id:98, question:"Qual é a parábola que fala de um homem com 100 ovelhas que perde uma e vai procurá-la?", options:["Parábola do grão de mostarda","Parábola dos talentos","Parábola da ovelha perdida","Parábola da rede"], correctIndex:2, explanation:"Na parábola da ovelha perdida, o pastor deixa as 99 ovelhas e vai procurar a que se perdeu. Ao encontrá-la, a carrega nos ombros com alegria.", reference:"Lucas 15:4-7", category:.jesus, propheticMeaning:"Jesus é o Bom Pastor que busca ativamente o pecador perdido. A alegria do pastor ao encontrar a ovelha reflete o gozo do céu por um pecador que se arrepente — somos preciosos ao coração de Deus."),
    QuizQuestion(id:99, question:"Quem era Zaqueu e o que aconteceu quando Jesus o encontrou?", options:["Um pescador que Jesus curou","Um sacerdote convertido","Um fariseu que perseguia cristãos","Um cobrador de impostos baixinho que..."], correctIndex:3, explanation:"Zaqueu, cobrador de impostos e muito rico, subiu numa amoreira para ver Jesus. Jesus o chamou pelo nome e foi hospedar-se em sua casa, e Zaqueu se arrependeu e devolveu o que havia roubado.", reference:"Lucas 19:2-8", category:.jesus, propheticMeaning:"Jesus dizendo 'Hoje a salvação entrou nesta casa' (Lc 19:9) mostra que a salvação é pessoal, imediata e transforma radicalmente a vida. Zaqueu é tipo de quem busca a Jesus com todo o empenho e o encontra."),
    QuizQuestion(id:100, question:"O que Jesus disse sobre quem receber uma criança em seu nome?", options:["Que o recebe a ele mesmo","Que receberá grande recompensa no céu","Que deve ensiná-la a lei","Que deve batizá-la imediatamente"], correctIndex:0, explanation:"Jesus disse: 'Quem receber esta criança em meu nome, me recebe a mim; e quem me recebe, recebe aquele que me enviou.'", reference:"Lucas 9:48", category:.jesus, propheticMeaning:"Jesus identificando-se com os pequenos e vulneráveis inverte a escala de valores do mundo. No Reino de Deus, a grandeza é medida pela humildade e serviço, não pelo poder ou status social."),
    QuizQuestion(id:101, question:"Qual é a parábola dos talentos e o que ela ensina?", options:["Que devemos ser generosos com os pobres","Que cada crente deve usar os dons","Que os ricos devem dar tudo aos pobres","Que o trabalho duro sempre recompensa"], correctIndex:1, explanation:"Na parábola dos talentos, o mestre distribui talentos aos servos antes de viajar. Os que multiplicaram foram elogiados; o que escondeu o talento foi condenado.", reference:"Mateus 25:14-30", category:.jesus, propheticMeaning:"Os talentos representam os dons espirituais e responsabilidades que Deus nos confia. Cristo voltará para uma prestação de contas — a parábola ensina mordomia fiel, serviço ativo e o perigo da omissão."),
    QuizQuestion(id:102, question:"O que Jesus disse que aconteceria com quem pedisse, buscasse e batesse?", options:["Que seria provado com dificuldades","Que Deus veria se era digno","Que receberia, acharia e lhe seria aberto","Que receberia depois de muito tempo"], correctIndex:2, explanation:"Jesus ensinou: 'Pedi e dar-se-vos-á; buscai e achareis; batei e abrir-se-vos-á', encorajando a oração persistente e confiante.", reference:"Mateus 7:7", category:.jesus, propheticMeaning:"A tríplice promessa (peça, busque, bata) mostra que Deus responde a quem persevera. A oração não muda a vontade de Deus, mas nos alinha a ela e nos conecta ao poder que transforma circunstâncias."),
    QuizQuestion(id:103, question:"O que Jesus disse sobre a pedra que os construtores rejeitaram?", options:["Que seria destruída","Que seria usada para o templo","Que ficaria no caminho","Que se tornou a pedra angular"], correctIndex:3, explanation:"Citando o Salmo 118:22, Jesus disse: 'A pedra que os construtores rejeitaram tornou-se a pedra angular', referindo-se a si mesmo como rejeitado por Israel mas escolhido por Deus.", reference:"Mateus 21:42; Salmos 118:22", category:.jesus, propheticMeaning:"Jesus é a Pedra Angular (Ef 2:20) sobre quem toda a Igreja é edificada. Sua rejeição por líderes religiosos e subsequente exaltação por Deus cumpre este salmo profético literalmente."),
    QuizQuestion(id:104, question:"Qual é a parábola das 10 virgens e o que ela ensina sobre o fim dos tempos?", options:["Que devemos estar preparados para a volta","Que devemos ser ricos para o julgamento","Que a pureza é o mais importante","Que devemos jejuar sempre"], correctIndex:0, explanation:"Cinco virgens prudentes levaram azeite extra para suas lamparinas; cinco loucas não levaram. Quando o noivo chegou tarde, as imprudentes foram excluídas por não estar preparadas.", reference:"Mateus 25:1-13", category:.jesus, propheticMeaning:"O azeite é símbolo do Espírito Santo. As virgens prudentes têm vida espiritual genuína; as loucas têm forma de piedade sem o Espírito. A parábola alerta: apenas a transformação real nos prepara para a eternidade."),
    QuizQuestion(id:105, question:"Quem eram os pais terrenos de Jesus?", options:["Zacarias e Isabel","José e Maria","Simão e Ana","Joaquim e Ana"], correctIndex:1, explanation:"Maria foi a mãe biológica de Jesus, concebendo-o pelo Espírito Santo; José foi seu pai legal e adotivo, da linhagem de Davi.", reference:"Lucas 1:27; Mateus 1:18", category:.jesus, propheticMeaning:"A dupla linhagem de Jesus (pela mãe e pelo pai adotivo) garante que ele cumpre as profecias: descendente de Davi pelo sangue (Rm 1:3) e herdeiro legal do trono de Davi (Mt 1:1-17)."),
    QuizQuestion(id:106, question:"O que aconteceu quando os Reis Magos visitaram Jesus?", options:["Jesus falou com eles","Eles o levaram para o Egito","Eles trouxeram ouro, incenso e mirra","Eles anunciaram sua chegada ao povo"], correctIndex:2, explanation:"Os Reis Magos (Magos do Oriente) trouxeram presentes: ouro, incenso e mirra, prostrando-se para adorar o recém-nascido Jesus em Belém.", reference:"Mateus 2:11", category:.jesus, propheticMeaning:"Os três presentes são proféticos: ouro = realeza (Jesus é Rei); incenso = sacerdócio (Jesus é Sumo Sacerdote que intercede); mirra = morte e sepultura (Jesus morreu por nós). Isaías 60:6 prefigurou isso."),
    QuizQuestion(id:107, question:"Por que José, Maria e Jesus fugiram para o Egito?", options:["Por causa de uma fome","Para cumprir a lei judaica","Para visitar parentes","Para escapar de Herodes que"], correctIndex:3, explanation:"Um anjo avisou José em sonho que Herodes procurava o menino para matá-lo. A família fugiu para o Egito e ficou lá até a morte de Herodes.", reference:"Mateus 2:13-14", category:.jesus, propheticMeaning:"'Do Egito chamei o meu Filho' (Os 11:1) se refere a Israel historicamente, mas Mateus vê o cumprimento em Jesus — o novo Israel, que como a nação, saiu do Egito para cumprir o propósito de Deus."),
    QuizQuestion(id:108, question:"Com que idade Jesus ficou no templo ensinando os doutores da lei?", options:["12 anos","5 anos","10 anos","15 anos"], correctIndex:0, explanation:"Aos 12 anos, enquanto os pais voltavam da Páscoa em Jerusalém, Jesus ficou no templo conversando com os doutores, que se maravilhavam com sua sabedoria.", reference:"Lucas 2:42-47", category:.jesus, propheticMeaning:"Jesus no templo aos 12 anos, 'nos negócios de seu Pai', revela sua consciência messiânica desde a infância. O Filho de Deus habitou entre os mestres humanos, ensinando com autoridade sobrenatural."),
    QuizQuestion(id:109, question:"Quem era João Batista em relação a Jesus?", options:["Irmão mais velho","Primo e precursor do Messias","Discípulo principal","Primo que não o reconhecia"], correctIndex:1, explanation:"João Batista era primo de Jesus (filho de Isabel, prima de Maria) e seu precursor — o mensageiro que preparou o caminho anunciando a vinda do Messias.", reference:"Lucas 1:36; João 1:23", category:.jesus, propheticMeaning:"João Batista cumpre Isaías 40:3 e Malaquias 3:1: a voz que clama no deserto preparando o caminho do Senhor. Ele é o 'Elias que havia de vir' (Mt 11:14), completando a profecia de Ml 4:5-6."),
    QuizQuestion(id:110, question:"O que Jesus disse ser em João 10:11?", options:["A Videira","A Porta","O Bom Pastor","A Ressurreição"], correctIndex:2, explanation:"Jesus declarou: 'Eu sou o Bom Pastor. O Bom Pastor dá a sua vida pelas ovelhas', distinguindo-se dos mercenários que abandonam o rebanho.", reference:"João 10:11", category:.jesus, propheticMeaning:"Ezequiel 34 prometeu que Deus mesmo apascentaria seu rebanho quando os pastores humanos falhassem. Jesus, ao declarar-se o Bom Pastor, cumpre essa promessa divina — Deus vindo pessoalmente cuidar de seu povo."),
    QuizQuestion(id:111, question:"O que Jesus disse a respeito das crianças quando os discípulos queriam afastá-las?", options:["'Deixai-as para depois'","'Ensinae-as primeiro a lei'","'Crianças não pertencem ao Reino agora'","'Deixai as crianças virem a mim e não as..."], correctIndex:3, explanation:"Jesus repreendeu os discípulos e disse: 'Deixai as crianças virem a mim, pois o Reino dos céus é delas.'", reference:"Mateus 19:14", category:.jesus, propheticMeaning:"Jesus valorizando crianças inverte a hierarquia cultural. No Reino de Deus, a humildade infantil — dependência total, fé simples e confiança — é o modelo de quem herda o Reino (Mt 18:3)."),
    QuizQuestion(id:112, question:"Que pergunta Jesus fez a Pedro em Cesareia de Filipe?", options:["'Quem dizem os homens que sou eu?'","'Pedro, você me ama?'","'Você vai me negar?'","'Você quer curar os doentes?'"], correctIndex:0, explanation:"Em Cesareia de Filipe, Jesus perguntou aos discípulos quem os homens diziam que ele era, e depois: 'Mas vós, quem dizeis que sou eu?' Pedro respondeu: 'Tu és o Cristo, o Filho do Deus vivo.'", reference:"Mateus 16:13-16", category:.jesus, propheticMeaning:"A pergunta 'Quem sou eu?' é a questão central de toda a teologia. A resposta de Pedro — 'Tu és o Cristo' — é a pedra sobre a qual a Igreja é edificada (Mt 16:18). É a confissão que salva."),
    QuizQuestion(id:113, question:"O que Jesus disse ser em João 15:1?", options:["A Luz do Mundo","A Videira Verdadeira","O Pão da Vida","A Porta das Ovelhas"], correctIndex:1, explanation:"Jesus disse: 'Eu sou a videira verdadeira e meu Pai é o agricultor', ensinando sobre a necessidade de permanecer nele para dar fruto.", reference:"João 15:1", category:.jesus, propheticMeaning:"Israel era chamado de vinha de Deus (Is 5:1-7) que não produziu fruto. Jesus é a Videira Verdadeira — o verdadeiro Israel que cumpre o chamado e cujos galhos (crentes) produzem fruto abundante ao permanecerem nele."),
    QuizQuestion(id:114, question:"Qual foi a última grande promessa que Jesus fez antes de ascender ao céu?", options:["'Voltarei em breve'","'Orai e jejuai e sereis fortes'","'Todo o poder me foi dado","'Batizai-vos e sereis salvos'"], correctIndex:2, explanation:"A Grande Comissão: 'Toda autoridade me foi dada no céu e na terra. Portanto ide e fazei discípulos de todas as nações, batizando-os e ensinando-os a guardar tudo o que vos ordenei.'", reference:"Mateus 28:18-20", category:.jesus, propheticMeaning:"A Grande Comissão é o cumprimento de Gênesis 12:3 (bênção para todas as nações) e Daniel 7:14 (domínio dado ao Filho do Homem sobre todas as nações). Jesus envia a Igreja para completar o plano de redenção universal."),
    QuizQuestion(id:115, question:"O que Jesus disse sobre amar os inimigos?", options:["'Evite seus inimigos'","'Apenas suporte seus inimigos'","'Deixe Deus lidar com seus inimigos'","'Amai os vossos inimigos e orai pelos"], correctIndex:3, explanation:"Jesus ensinou: 'Amai os vossos inimigos e orai pelos que vos perseguem', revelando um padrão de amor sobrenatural que reflete o próprio caráter de Deus.", reference:"Mateus 5:44", category:.jesus, propheticMeaning:"Amar inimigos é o distintivo do cristão e o DNA do evangelho. Cristo mesmo amou seus inimigos até a morte. Esse amor sobrenatural só é possível pelo Espírito Santo, testemunho vivo do poder transformador do evangelho."),
    QuizQuestion(id:116, question:"O que aconteceu quando Jesus andou sobre as águas?", options:["Pedro saiu do barco","Todos os discípulos saíram para ele","O mar ficou calmo imediatamente","Os peixes apareceram em abundância"], correctIndex:0, explanation:"Pedro pediu para ir até Jesus sobre as águas. Saiu do barco e caminhou, mas quando viu o vento forte, teve medo, começou a afundar e clamou: 'Senhor, salva-me!'", reference:"Mateus 14:28-30", category:.jesus, propheticMeaning:"Pedro caminhando sobre as águas pela fé, afundando pela dúvida, ilustra a vida cristã: enquanto os olhos estão em Jesus temos poder sobrenatural; quando desviamos para as circunstâncias, afundamos. A solução é sempre clamar a Cristo."),
    QuizQuestion(id:117, question:"Quais eram os nomes dos três discípulos mais próximos de Jesus?", options:["Pedro, Paulo e João","Pedro, Tiago e João","André, Filipe e Bartolomeu","Mateus, Marcos e Lucas"], correctIndex:1, explanation:"Pedro, Tiago e João formavam o círculo íntimo de Jesus, presenciando a transfiguração, a ressurreição da filha de Jairo e a agonia em Getsêmani.", reference:"Mateus 17:1; Marcos 5:37; Mateus 26:37", category:.jesus, propheticMeaning:"Os três testemunhas especiais cumprem a lei de Deuteronômio 19:15: 'por boca de duas ou três testemunhas toda palavra será confirmada.' Os momentos mais gloriosos e dolorosos de Jesus foram confirmados por testemunhas oculares."),
    QuizQuestion(id:118, question:"O que Jesus fez na sinagoga em seu primeiro sermão em Nazaré?", options:["Curou um cego","Expulsou demônios","Leu Isaías 61 e disse","Batizou discípulos"], correctIndex:2, explanation:"Jesus leu Isaías 61:1-2 (ungido para pregar boas novas aos pobres, libertar os cativos) e declarou: 'Hoje se cumpriu esta Escritura.'", reference:"Lucas 4:17-21", category:.jesus, propheticMeaning:"Isaías 61 é o 'manifesto' do ministério messiânico. Jesus declarando seu cumprimento confirma que ele é o Servo Ungido do Senhor, o Messias prometido. Mas ele parou antes de 'o dia da vingança do nosso Deus' — que virá em sua segunda vinda."),
    QuizQuestion(id:119, question:"O que Jesus prometeu ao ladrão arrependido na cruz?", options:["'Você me encontrará no paraíso'","'Serás salvo após julgamento'","'Teus pecados são grandes demais'","'Hoje estarás comigo no Paraíso'"], correctIndex:3, explanation:"O ladrão arrependido pediu que Jesus se lembrasse dele, e Jesus respondeu: 'Hoje estarás comigo no Paraíso', mostrando que a salvação pode ser recebida no último momento.", reference:"Lucas 23:43", category:.jesus, propheticMeaning:"A salvação do ladrão na cruz demonstra que a salvação é pela graça pela fé, não por obras ou méritos. Mesmo nos últimos momentos de vida, o arrependimento genuíno recebe o dom gratuito da vida eterna."),
    QuizQuestion(id:120, question:"O que Jesus disse ser em João 11:25?", options:["A Ressurreição e a","O Pão da Vida","A Porta","O Caminho"], correctIndex:0, explanation:"Jesus disse a Marta: 'Eu sou a ressurreição e a vida. Quem crê em mim, ainda que morra, viverá; e todo o que vive e crê em mim não morrerá eternamente.'", reference:"João 11:25-26", category:.jesus, propheticMeaning:"Esta declaração 'Eu Sou' vincula Jesus ao nome divino (Ex 3:14) e revela que a ressurreição não é apenas um evento futuro — ela é uma Pessoa. Cristo não apenas dá vida; ele é a fonte e substância da vida eterna."),
]
